-- supabase/seed_stores.sql
-- Run this in Supabase SQL Editor after schema migration
-- Safe to re-run (upsert)

ON CONFLICT (store_code)
DO UPDATE SET
  name           = EXCLUDED.name,
  store_incharge = EXCLUDED.store_incharge,
  store_phone    = EXCLUDED.store_phone,
  am             = EXCLUDED.am,
  am_number      = EXCLUDED.am_number,
  address        = EXCLUDED.address;
